async function populateEditDropdowns(writ) {
  // Populate type dropdown
  const typeSel = document.getElementById(`edit-type-${writ.id}`);
  if (typeSel) {
    try {
      const types = await api('GET', '/api/writ/types');
      typeSel.innerHTML = '';
      for (const t of types) {
        const opt = document.createElement('option');
        opt.value = t.name;
        opt.textContent = t.name;
        if (t.description) opt.title = t.description;
        if (t.name === writ.type) opt.selected = true;
        typeSel.appendChild(opt);
      }
    } catch (e) {
      typeSel.innerHTML = `<option value="${escAttr(writ.type ?? '')}">${escHtml(writ.type ?? '')}</option>`;
    }
  }

  // Populate codex dropdown
  const codexSel = document.getElementById(`edit-codex-${writ.id}`);
  if (codexSel) {
    try {
      const codexes = await api('GET', '/api/codex/list');
      codexSel.innerHTML = '<option value="">(none)</option>';
      for (const c of codexes) {
        const opt = document.createElement('option');
        opt.value = c.name;
        opt.textContent = c.name;
        if (c.name === writ.codex) opt.selected = true;
        codexSel.appendChild(opt);
      }
    } catch (e) {
      codexSel.innerHTML = `<option value="">(none)</option>`;
      if (writ.codex) {
        codexSel.innerHTML += `<option value="${escAttr(writ.codex)}" selected>${escHtml(writ.codex)}</option>`;
      }
    }
  }
}

function handleDetailAction(action, id, btn, td, writ) {
  if (action === 'save-edit') {
    doSaveEdit(id, btn, td);
  } else if (action === 'publish') {
    doPublish(id, btn, td);
  } else if (action === 'cancel') {
    showConfirm(id, 'cancel', btn, td, false);
  } else if (action === 'complete') {
    showConfirm(id, 'complete', btn, td, true);
  } else if (action === 'fail') {
    showConfirm(id, 'fail', btn, td, true);
  } else if (action === 'repost') {
    openRepost(writ);
  } else if (action === 'unlink') {
    doUnlink(btn.dataset.source, btn.dataset.target, btn.dataset.label, btn, id);
  } else if (action === 'addlink') {
    const targetInput = document.getElementById(`link-target-${id}`);
    const labelInput = document.getElementById(`link-label-${id}`);
    const kindSelect = document.getElementById(`link-kind-${id}`);
    const errEl = document.getElementById(`link-error-${id}`);
    const kindValue = kindSelect ? kindSelect.value : '';
    doAddLink(id, targetInput.value.trim(), labelInput.value.trim(), kindValue, btn, errEl, targetInput, labelInput, kindSelect);
  }
}

