async function loadCodexes() {
  const sel = document.getElementById('post-codex-select');
  const errEl = document.getElementById('post-codex-error');
  const submitBtn = document.getElementById('post-submit-btn');

  let codexes;
  try {
    codexes = await api('GET', '/api/codex/list');
  } catch (e) {
    console.error('Failed to load codexes:', e);
    sel.innerHTML = '<option value="">No codexes available</option>';
    sel.disabled = true;
    submitBtn.disabled = true;
    showError(errEl, 'Could not load codexes. A codex is required to post writs.');
    return;
  }

  if (!codexes || codexes.length === 0) {
    sel.innerHTML = '<option value="">No codexes configured</option>';
    sel.disabled = true;
    submitBtn.disabled = true;
    showError(errEl, 'No codexes are configured. A codex is required to post writs.');
    return;
  }

  // Populate dropdown
  sel.innerHTML = '';
  if (codexes.length > 1) {
    const placeholder = document.createElement('option');
    placeholder.value = '';
    placeholder.textContent = 'Select a codex…';
    sel.appendChild(placeholder);
  }
  for (const c of codexes) {
    const opt = document.createElement('option');
    opt.value = c.name;
    opt.textContent = c.name;
    if (c.cloneStatus !== 'ready') opt.title = `Status: ${c.cloneStatus}`;
    sel.appendChild(opt);
  }
  // Pre-select if only one
  if (codexes.length === 1) {
    sel.value = codexes[0].name;
  }
  sel.disabled = false;
  submitBtn.disabled = false;
  clearError(errEl);
}

// ── Post form ───────────────────────────────────────────────────────

function openPostForm() {
  const section = document.getElementById('post-section');
  section.classList.add('open');
  document.getElementById('post-title-input').focus();
}

function closePostForm() {
  const section = document.getElementById('post-section');
  section.classList.remove('open');
  // Reset repost state
  repostSourceId = null;
  document.getElementById('post-title').textContent = 'New Writ';
}

function clearPostForm() {
  document.getElementById('post-title-input').value = '';
  document.getElementById('post-body-input').value = '';
  document.getElementById('post-draft-checkbox').checked = false;
  clearError(document.getElementById('post-error'));
  clearError(document.getElementById('post-warn'));
  clearError(document.getElementById('post-codex-error'));
  // Reset type to default
  const typeSel = document.getElementById('post-type-select');
  for (const opt of typeSel.options) {
    if (opt.dataset.isDefault === 'true') opt.selected = true;
  }
  // Reset codex to first item (pre-selected if single, placeholder if multiple)
  const codexSel = document.getElementById('post-codex-select');
  if (!codexSel.disabled && codexSel.options.length > 0) {
    codexSel.selectedIndex = 0;
  }
}

function openRepost(writ) {
  // If in detail view, switch back to list view first
  document.getElementById('writ-detail-view').style.display = 'none';
  document.getElementById('writ-list-view').style.display = '';
  openPostForm();
  document.getElementById('post-title').textContent = 'Repost Writ';
  document.getElementById('post-title-input').value = `[Repost] ${writ.title ?? ''}`;
  document.getElementById('post-body-input').value = writ.body ?? '';
  // Set type
  const typeSel = document.getElementById('post-type-select');
  for (const opt of typeSel.options) {
    if (opt.value === writ.type) {
      opt.selected = true;
      break;
    }
  }
  // Set codex if available
  if (writ.codex) {
    const codexSel = document.getElementById('post-codex-select');
    for (const opt of codexSel.options) {
      if (opt.value === writ.codex) {
        opt.selected = true;
        break;
      }
    }
  }

