1	/**
2	 * Unit tests for writ type filter logic in writs/index.html.
3	 *
4	 * Extracts and tests the pure logic behind the type filter bar:
5	 * - Button generation from writ types
6	 * - Default type selection (all types selected)
7	 * - Multi-select filter toggling via setTypeFilter
8	 *
9	 * Uses a minimal DOM shim to validate element creation without a browser.
10	 */
11	
12	import { describe, it, beforeEach } from 'node:test';
13	import assert from 'node:assert/strict';
14	
15	// ── Minimal DOM shim ────────────────────────────────────────────────
16	
17	/** Tiny element stub sufficient for the filter bar logic. */
18	class FakeElement {
19	  constructor(tag) {
20	    this.tagName = tag.toUpperCase();
21	    this.className = '';
22	    this.textContent = '';
23	    this.title = '';
24	    this.innerHTML = '';
25	    this.dataset = {};
26	    this.children = [];
27	    this._listeners = {};
28	  }
29	
30	  appendChild(child) {
31	    this.children.push(child);
32	    return child;
33	  }
34	
35	  querySelector(selector) {
36	    // Support '.type-filter-btn[data-type=""]' and ':not(...)' patterns
37	    const btns = this.querySelectorAll('.type-filter-btn');
38	    if (selector.includes('data-type=""')) {
39	      return btns.find(b => b.dataset.type === '') ?? null;
40	    }
41	    return btns[0] ?? null;
42	  }
43	
44	  querySelectorAll(selector) {
45	    // Only supports '.type-filter-btn' variants
46	    const allBtns = this.children.filter(c =>
47	      c.className.includes('type-filter-btn'),
48	    );
49	    if (selector.includes(':not([data-type=""])')) {
50	      return allBtns.filter(b => b.dataset.type !== '');
51	    }
52	    return allBtns;
53	  }
54	
55	  addEventListener(event, fn) {
56	    if (!this._listeners[event]) this._listeners[event] = [];
57	    this._listeners[event].push(fn);
58	  }
59	
60	  click() {
61	    for (const fn of this._listeners.click ?? []) fn();
62	  }
63	
64	  get classList() {
65	    const self = this;
66	    return {
67	      toggle(cls, force) {
68	        const classes = self.className.split(/\s+/).filter(Boolean);
69	        const idx = classes.indexOf(cls);
70	        if (force && idx === -1) classes.push(cls);
71	        if (!force && idx !== -1) classes.splice(idx, 1);
72	        self.className = classes.join(' ');
73	      },
74	      add(cls) {
75	        const classes = self.className.split(/\s+/).filter(Boolean);
76	        if (!classes.includes(cls)) classes.push(cls);
77	        self.className = classes.join(' ');
78	      },
79	      contains(cls) {
80	        return self.className.split(/\s+/).includes(cls);
81	      },
82	    };
83	  }
84	}
85	
86	function createElement(tag) {
87	  return new FakeElement(tag);
88	}
89	
90	// ── Extracted logic (mirrors index.html) ────────────────────────────
91	
92	/** Shared state — mirrors the IIFE variable in index.html. */
93	let currentType = new Set();
94	
95	/**
96	 * Builds type filter buttons from a types array into a bar element.
97	 * Returns the currentType Set for testability.
98	 */
99	function buildTypeFilterBar(types, bar) {
100	  // Clear existing buttons (keep label span)
101	  bar.innerHTML = '';
102	  bar.children = [];
103	
104	  // Label
105	  const label = createElement('span');
106	  label.textContent = 'Type:';
107	  bar.appendChild(label);
108	
109	  // "All" button
110	  const allBtn = createElement('button');
111	  allBtn.className = 'btn type-filter-btn';
112	  allBtn.dataset.type = '';
113	  allBtn.textContent = 'All';
114	  bar.appendChild(allBtn);
115	
116	  // One button per known type
117	  for (const t of types) {
118	    const btn = createElement('button');
119	    btn.className = 'btn type-filter-btn';
120	    btn.dataset.type = t.name;
121	    btn.textContent = t.name;
122	    if (t.description) btn.title = t.description;
123	    bar.appendChild(btn);
124	  }
125	
126	  // Default: select all types
127	  currentType = new Set(types.map(t => t.name));
128	  bar.querySelectorAll('.type-filter-btn').forEach(btn => {
129	    btn.classList.add('active-filter');
130	  });
131	
132	  return currentType;
133	}
