137	 * Does not call loadWrits — just updates state and button classes.
138	 */
139	function applyTypeFilter(bar, type) {
140	  const allBtn = bar.querySelector('.type-filter-btn[data-type=""]');
141	  const typeBtns = bar.querySelectorAll('.type-filter-btn').filter(b => b.dataset.type !== '');
142	  const allTypeNames = typeBtns.map(b => b.dataset.type);
