150	    if (allActive) {
151	      // "All" was active — deselect everything except the clicked type
152	      currentType = new Set([type]);
153	    } else {
154	      // Normal toggle
155	      if (currentType.has(type)) {
156	        currentType.delete(type);
157	      } else {
158	        currentType.add(type);
159	      }
160	    }
161	  }
162	
163	  // Update button visual state
164	  const nowAllActive = allTypeNames.length > 0 && allTypeNames.every(t => currentType.has(t));
165	  allBtn.classList.toggle('active-filter', nowAllActive);
166	  typeBtns.forEach(btn => {
167	    btn.classList.toggle('active-filter', currentType.has(btn.dataset.type));
168	  });
169	}
