content.content:
1	/**
2	 * patron-anima clockwork engine.
3	 *
4	 * Between `inventory-check` and `decision-review`, consults a configured
5	 * Patron Anima to principle-check every decision the primer produced. Any
6	 * decision the anima confirms (including `low`-confidence confirms),
7	 * overrides, or fills in is set on the PlanDoc with its `selection` value
8	 * — `decision-review` then auto-skips it via the existing
9	 * "primer pre-decides → patron-input omitted" semantics. The narrow
10	 * abstention cases flow through unfilled for the patron to answer.
11	 *
12	 * Operational discipline (the tailored work prompt):
13	 *   The anima runs under a checked-in operational prompt — the static
14	 *   portions live in `patron-anima-prompt.md` (packaged alongside the
15	 *   plugin) and are loaded at startup; per-decision content (ids,
16	 *   questions, options, primer recommendations) is interpolated in this
17	 *   module at build time. The prompt encodes the engine's mode discipline,
18	 *   which is structurally distinct from the anima's taste (which lives in
19	 *   the role's system prompt):
20	 *
21	 *     - One option per decision. `selection` must be one of the offered
22	 *       option keys — no custom answers, no free-text, no multi-select.
23	 *     - Principle-structural confidence. `high` = a single principle from
24	 *       the role fires cleanly; `med` = multiple principles conflict and
25	 *       the anima resolves the conflict; `low` = no principle speaks and
26	 *       the anima confirms the primer's recommendation. `low` is a
27	 *       first-class emission path, not a placeholder and not reserved for
28	 *       abstention — principle-absence has the concrete meaning "no
29	 *       principled basis to differ; confirm the primer."
30	 *     - Narrow abstention by omission. The anima leaves a decision out of
31	 *       its emission array only in two cases: *irresolvable principle
32	 *       conflict* (multiple principles conflict and the anima cannot
33	 *       resolve without inventing a principle hierarchy the patron has
34	 *       not articulated) and *broken decision frame* (the question or
35	 *       options are incoherent as posed, so no valid emission would be
36	 *       faithful to the patron's intent). Every other case — including
37	 *       principle-absence — resolves to a first-class emission. The
38	 *       engine treats a missing verdict as "unfilled" and flows it
39	 *       through to `decision-review` in the normal path.
40	 *     - Out-of-lane prohibition. The draft worktree `cwd` passed to the
41	 *       anima permits filesystem access, but the prompt explicitly
42	 *       forbids file reads, grep, codebase audit, and second-guessing
43	 *       the primer's framing. The anima's entire input is the role's
44	 *       principles plus the decisions listed in the prompt.
45	 *
46	 * Config:
47	 *   guild.json["astrolabe"]["patronRole"]
48	 *     Qualified role name for the Patron Anima (e.g. 'guild.patron').
49	 *     When unset or empty, this engine no-ops — the pipeline proceeds
50	 *     exactly as it did before the engine existed.
51	 *
52	 * Run → Collect protocol:
53	 *   run()     → loads the plan; builds a single prompt covering all
54	 *                reviewable decisions; launches an anima session via
55	 *                `animator.summon()`. Returns
56	 *                `{ status: 'launched', sessionId }`.
57	 *   collect() → reads the session's `output` from Stacks, parses the
58	 *                emitted JSON verdict array, applies verdicts to the
59	 *                PlanDoc, and records each verdict as `Decision.patron`.
60	 *
61	 * Output contract (the anima is asked for):
62	 *   The session's final message must be a single fenced JSON block
63	 *   containing an array of verdict objects. Each object:
64	 *     - `id`         — the decision id
65	 *     - `verdict`    — 'confirm' | 'override' | 'fill-in'
66	 *     - `selection`  — one of the decision's offered option keys
67	 *     - `confidence` — 'high' | 'med' | 'low' (`low` = confirm the
68	 *                      primer on principle-absence; first-class emission)
69	 *     - `rationale`  — short free-text note (optional)
70	 *   Decisions the anima abstains on — the two narrow cases above — are
71	 *   absent from the array; the engine and parser treat absence as
72	 *   "unfilled, surface to patron."
73	 *
74	 * Exhaustiveness:
75	 *   Single pass. Any decision not carrying a well-formed verdict —
76	 *   because the anima abstained (omitted it), emitted malformed JSON,
77	 *   picked an unknown option, or the session failed entirely — is left
78	 *   unfilled on the PlanDoc and flows to `decision-review` in the
79	 *   normal flow. The engine does not retry.
80	 */
81	
82	import { readFileSync } from 'node:fs';
83	import { dirname, resolve } from 'node:path';
84	import { fileURLToPath } from 'node:url';
85	
86	import { guild } from '@shardworks/nexus-core';
87	import type { EngineDesign, EngineRunContext, EngineRunResult } from '@shardworks/fabricator-apparatus';
88	import type { Book } from '@shardworks/stacks-apparatus';
89	import type { StacksApi } from '@shardworks/stacks-apparatus';
90	import type { AnimatorApi, SessionDoc } from '@shardworks/animator-apparatus';
91	import type { WritDoc } from '@shardworks/clerk-apparatus';
92	import { resolvePatronRole } from '../astrolabe.ts';
93	import type { Decision, PatronEmission, PlanDoc } from '../types.ts';
94	
95	// ── Prompt template ──────────────────────────────────────────────────
96	
97	const __filename = fileURLToPath(import.meta.url);
98	const __dirname = dirname(__filename);
99	
100	/**
101	 * The static portion of the patron-anima operational prompt, loaded at module
102	 * load time from the checked-in markdown file packaged alongside this plugin.
103	 * The sentinel `{{DECISIONS}}` is replaced by the per-decision listing at
104	 * prompt-build time. The markdown file lives at the package root so it is
105	 * reachable via the same relative path from both `src/engines/` (source
106	 * mode) and `dist/engines/` (published distribution).
107	 */
108	const PROMPT_TEMPLATE: string = readFileSync(
109	  resolve(__dirname, '../../patron-anima-prompt.md'),
110	  'utf-8',
111	);
112	
113	const DECISIONS_PLACEHOLDER = '{{DECISIONS}}';
114	
115	// ── Helpers ──────────────────────────────────────────────────────────
116	
117	/** Reviewable = not yet pre-decided by the primer. Mirrors decision-review. */
118	function reviewableDecisions(plan: PlanDoc): Decision[] {
119	  return (plan.decisions ?? []).filter(d => d.selected === undefined);
120	}
121	
122	/**
123	 * Assemble the patron work prompt from the reviewable decisions.
124	 *
125	 * The static portion (preamble, mode discipline, out-of-lane prohibition,
126	 * output contract, worked example) lives in `patron-anima-prompt.md` and is
127	 * loaded into `PROMPT_TEMPLATE` at module load. This function renders each
128	 * reviewable decision — question, optional context, options, optional
129	 * primer recommendation / rationale — and substitutes the listing into
130	 * the template's `{{DECISIONS}}` placeholder.
131	 */
132	export function buildPatronPrompt(decisions: Decision[]): string {
133	  const lines: string[] = [];
134	
135	  for (const decision of decisions) {
136	    lines.push(`### ${decision.id}: ${decision.question}`);
137	    if (decision.context) {
138	      lines.push('');
139	      lines.push(`Context: ${decision.context}`);
140	    }
141	    lines.push('');
142	    lines.push('Options:');
143	    for (const [key, label] of Object.entries(decision.options)) {
144	      lines.push(`- \`${key}\` — ${label}`);
145	    }
146	    if (decision.recommendation) {
147	      lines.push('');
148	      const recLabel = decision.options[decision.recommendation] ?? decision.recommendation;
149	      lines.push(
150	        `Primer recommendation: \`${decision.recommendation}\` (${recLabel})`,
151	      );
152	      if (decision.rationale) {
153	        lines.push(`Primer rationale: ${decision.rationale}`);
154	      }
155	    } else {
156	      lines.push('');
157	      lines.push('Primer recommendation: (none — you must fill in)');
158	    }
159	    lines.push('');
160	  }
161	
162	  // Drop the trailing blank line so the substitution sits cleanly in the
163	  // template's final section.
164	  const decisionsBlock = lines.join('\n').replace(/\n+$/, '');
165	
166	  return PROMPT_TEMPLATE.replace(DECISIONS_PLACEHOLDER, decisionsBlock);
167	}
168	
169	/** Extract the last fenced JSON block from an anima's output. Returns null if none. */
170	export function extractJsonBlock(output: string): string | null {
171	  // Prefer ```json ... ``` fenced blocks; fall back to plain ``` ... ```.
172	  const jsonFence = /```(?:json)?\s*([\s\S]*?)```/gi;
173	  let match: RegExpExecArray | null;
174	  let last: string | null = null;
175	  while ((match = jsonFence.exec(output)) !== null) {
176	    last = match[1].trim();
177	  }
178	  if (last !== null) return last;
179	  // Last-ditch: try the output verbatim if it starts with `[` or `{`.
180	  const trimmed = output.trim();
181	  if (trimmed.startsWith('[') || trimmed.startsWith('{')) return trimmed;
182	  return null;
183	}
184	
185	export interface RawVerdict {
186	  id?: unknown;
187	  verdict?: unknown;
188	  selection?: unknown;
189	  confidence?: unknown;
190	  rationale?: unknown;
191	}
192	
193	/**
194	 * Parse the anima's JSON emission into a map keyed by decision id. Invalid
195	 * entries are dropped silently — the engine treats missing verdicts as
196	 * "leave the decision unfilled" and relies on `decision-review` to catch
197	 * them in the normal flow.
198	 */
199	export function parseEmission(
200	  output: string,
201	  decisions: Decision[],
202	): Map<string, PatronEmission> {
203	  const result = new Map<string, PatronEmission>();
204	  const block = extractJsonBlock(output);
205	  if (block === null) return result;
206	
207	  let parsed: unknown;
208	  try {
209	    parsed = JSON.parse(block);
210	  } catch {
211	    return result;
212	  }
213	
214	  // Accept either a bare array or an object with an `emissions` / `verdicts`
215	  // array field — be lenient about the outer shape so small model quirks
216	  // don't cost a whole round.
217	  let entries: unknown[];
218	  if (Array.isArray(parsed)) {
219	    entries = parsed;
220	  } else if (parsed && typeof parsed === 'object') {
221	    const obj = parsed as Record<string, unknown>;
222	    const maybe = obj.emissions ?? obj.verdicts ?? obj.decisions;
223	    entries = Array.isArray(maybe) ? maybe : [];
224	  } else {
225	    return result;
226	  }
227	
228	  const decisionById = new Map(decisions.map(d => [d.id, d]));
229	
230	  for (const rawEntry of entries) {
231	    if (!rawEntry || typeof rawEntry !== 'object') continue;
232	    const raw = rawEntry as RawVerdict;
233	    if (typeof raw.id !== 'string') continue;
234	    const decision = decisionById.get(raw.id);
235	    if (!decision) continue;
236	
237	    const verdict = raw.verdict;
238	    if (verdict !== 'confirm' && verdict !== 'override' && verdict !== 'fill-in') continue;
239	
240	    if (typeof raw.selection !== 'string') continue;
241	    if (!(raw.selection in decision.options)) continue;
242	
243	    const confidence = raw.confidence;
244	    if (confidence !== 'low' && confidence !== 'med' && confidence !== 'high') continue;
245	
246	    // `confirm` must agree with the primer's recommendation. If it doesn't,
247	    // treat the verdict as malformed — don't silently relabel it. Defends
248	    // against a model that says "confirm" but picks a different option.
249	    if (verdict === 'confirm') {
250	      if (!decision.recommendation || decision.recommendation !== raw.selection) {
251	        continue;
252	      }
253	    }
254	
255	    // `fill-in` requires there was no primer recommendation.
256	    if (verdict === 'fill-in' && decision.recommendation) {
257	      // Accept but only if the selection genuinely differs — otherwise
258	      // relabelling a confirm as fill-in is a model quirk we tolerate.
259	      // (Either way the `selected` resolution is the same.)
260	    }
261	
262	    // `override` requires a recommendation existed and differs from selection.
263	    if (verdict === 'override') {
264	      if (!decision.recommendation) continue;
265	      if (decision.recommendation === raw.selection) continue;
266	    }
267	
268	    const emission: PatronEmission = {
269	      verdict,
270	      selection: raw.selection,
271	      confidence,
272	    };
273	    if (typeof raw.rationale === 'string' && raw.rationale.length > 0) {
274	      emission.rationale = raw.rationale;
275	    }
276	    result.set(decision.id, emission);
277	  }
278	
279	  return result;
280	}
281	
282	// ── Engine factory ───────────────────────────────────────────────────
283	
284	export function createPatronAnimaEngine(getPlansBook: () => Book<PlanDoc>): EngineDesign {
285	  return {
286	    id: 'astrolabe.patron-anima',
287	
288	    async run(
289	      givens: Record<string, unknown>,
290	      context: EngineRunContext,
291	    ): Promise<EngineRunResult> {
292	      const planId = givens.planId;
293	      if (typeof planId !== 'string' || planId.length === 0) {
294	        throw new Error('patron-anima engine requires a non-empty string "planId" given.');
295	      }
296	
297	      const book = getPlansBook();
298	      const plan = await book.get(planId);
299	      if (!plan) {
300	        throw new Error(`Plan "${planId}" not found.`);
301	      }
302	
